94.content:
arena:
  meta:
    type: "PVP排名/资源获取"
    curr: "竞技场积分 (胜+2, 负-2, 连胜+)"
    tiers: "一阶 ~ 九阶 (每阶独立排名)"
3阶前只能匹配同乐园的人
  store_goods: # 积分兑换列表
    res:
      - {n: 灵魂结晶(小/中), use: 早期核心来源, note: 限量刷新}
      - {n: 乐园币, note: 积分兑换汇率低, 不推荐}
    consumables:
      - {n: 竞技场专用恢复药剂, p: 积分换取, e: 仅场内/休息区有效, cheap: true}
    gear:
      - {n: 角斗士装备, type: 过渡装, note: 属性平庸}

  ranking_rewards: # 真正的价值所在
    mech: "排名每上升一名发邮件奖励乐园币/灵魂结晶"
    top_10:
      - {n: 强者宝箱, freq: 每日/每周结算, pool: [灵魂结晶, 装备, 稀有道具]}
    top_3:
      - {n: 专属权限, e: 观战收费权, 匹配优先权}
    top_1: # 苏晓的目标
      - {n: 强者证明(徽章), unique: true, use: 兑换[猎魔套装]组件(猎魔之魂)}
      - {n: 首席霸主挂饰, e: 象征意义 + 特殊属性}

  special_mech:
    - {n: 免费恢复, e: 战斗结束免费修复肉体损伤(不含法力枯竭)}
    - {n: 保护机制, e: 连败掉分保护/新人保护}

114.content:
【四阶衍生世界库】

四阶核心特征：

歼星级战力： 摧毁行星是常规手段，波及恒星系是爆发状态。

虚空接触： 正式接触“虚空”概念，遭遇虚空种族、古神本尊、深渊行者。

tier_4_worlds:
  - { id: 1, name: "龙珠Z - 沙鲁游戏", entry_point: "完全体沙鲁宣布举办沙鲁游戏，挑战全地球强者。" }
  - { id: 2, name: "战锤40K - 基因原体苏醒", entry_point: "基里曼在马格拉格苏醒，大裂隙撕裂银河。" }
  - { id: 3, name: "遮天 - 星空古路", entry_point: "叶凡踏上星空古路，太古祖王与人族圣人大战。" }
  - { id: 4, name: "一拳超人 - 宇宙饿狼篇", entry_point: "饿狼接受神明力量，开启宇宙辐射模式，对战埼玉。" }
  - { id: 5, name: "Fate/Grand Order - 奥林波斯", entry_point: "机神宙斯准备发射空洞炮，破神同盟集结。" }
  - { id: 6, name: "漫威漫画 - 湮灭虫族", entry_point: "湮灭虫皇率领亿万虫群从负空间涌入正宇宙。" }
  - { id: 7, name: "完美世界 - 三千州争霸", entry_point: "石昊登临上界，仙殿传人出世，初代天骄混战。" }
  - { id: 8, name: "圣斗士星矢 - 极乐净土", entry_point: "星矢穿过超次元空间抵达极乐净土，死神现身。" }
  - { id: 9, name: "诡秘之主 - 愚者成神", entry_point: "愚者成神仪式开启，阿蒙窃取门途径权柄。" }
  - { id: 10, name: "吞噬星空 - 原始宇宙", entry_point: "罗峰进入混沌城修炼，不朽神灵神国战开启。" }
  - { id: 11, name: "天元突破 - 反螺旋族篇", entry_point: "超银河红莲螺岩诞生，反螺旋族干涉概率。" }
  - { id: 12, name: "死神 - 全知全能", entry_point: "友哈巴赫吞噬灵王，开启改写未来的能力。" }
  - { id: 13, name: "星际迷航 - Q连续体", entry_point: "种族8472从液态空间入侵，Q审判人类文明。" }
  - { id: 14, name: "美食的俘虏 - 宇宙NEO", entry_point: "阿卡西亚复活，NEO开始吞噬星系与时间。" }
  - { id: 15, name: "暗黑破坏神 - 原罪之战", entry_point: "乌迪西安觉醒奈非天之力，用意志重塑物质。" }
  - { id: 16, name: "仙逆 - 踏天之途", entry_point: "王林对抗界外大能，本源法则在星辰间碰撞。" }
  - { id: 17, name: "三体 - 二向箔打击", entry_point: "歌者投掷二向箔，太阳系空间维度开始坍缩。" }
  - { id: 18, name: "魔兽世界 - 燃烧军团终局", entry_point: "萨格拉斯之剑刺向艾泽拉斯，阿古斯决战。" }
